#!/bin/bash
# lapseiq-mcp v2 deploy â€” switch legacy SSE to Streamable HTTP transport
# Fixes Cloudflare 524 on long-lived SSE streams.
# Generated 2026-05-17.
set -e

echo '====================================================================='
echo '  lapseiq-mcp v2 deploy: legacy SSE -> Streamable HTTP'
echo '====================================================================='

cd /root/lapseiq-mcp

# 1. Backup current server.mjs
BACKUP="/root/lapseiq-mcp/server.mjs.bak.$(date +%Y%m%d-%H%M%S)"
cp server.mjs $BACKUP
echo "[1/6] Backed up old server.mjs to $BACKUP"

# 2. Write new server.mjs from base64
cat > /tmp/server-v2.mjs.b64 << 'B64EOF'

B64EOF
base64 -d /tmp/server-v2.mjs.b64 > /root/lapseiq-mcp/server.mjs.new
rm /tmp/server-v2.mjs.b64
echo "[2/6] Decoded new server.mjs ($(wc -l < /root/lapseiq-mcp/server.mjs.new) lines)"

# 3. Syntax check before swap
if node -c /root/lapseiq-mcp/server.mjs.new; then
  mv /root/lapseiq-mcp/server.mjs.new /root/lapseiq-mcp/server.mjs
  echo '[3/6] Syntax OK; new server.mjs in place'
else
  echo '[3/6] FAIL: syntax check failed; old server.mjs unchanged'
  rm /root/lapseiq-mcp/server.mjs.new
  exit 1
fi

# 4. Restart pm2
pm2 restart lapseiq-mcp
echo '[4/6] pm2 restarted'

# 5. Wait + health smoke (local + public)
sleep 3
echo '[5/6] Smoke tests:'
echo -n '  local  /health -> '
curl -sS -o - -w ' HTTP %{http_code}\n' http://127.0.0.1:4001/health
echo -n '  public /_mcp/health -> '
curl -sS -o - -w ' HTTP %{http_code}\n' https://demo.lapseiq.com/_mcp/health
echo -n '  POST /_mcp/sse with auth (should NOT 524) -> '
TOKEN=$(grep MCP_AUTH_TOKEN /root/lapseiq-mcp/.env | cut -d= -f2)
curl -sS --max-time 12 -X POST -H "Authorization: Bearer $TOKEN" -H 'Content-Type: application/json' -H 'Accept: application/json, text/event-stream' -d '{"jsonrpc":"2.0","id":1,"method":"initialize","params":{"protocolVersion":"2024-11-05","capabilities":{},"clientInfo":{"name":"deploy-smoke","version":"0.1"}}}' -o - -w '\n    HTTP %{http_code}\n' https://demo.lapseiq.com/_mcp/sse

# 6. Show pm2 status + last few log lines
echo ''
echo '[6/6] pm2 status + recent logs:'
pm2 list
echo ''
pm2 logs lapseiq-mcp --lines 15 --nostream

echo ''
echo '====================================================================='
echo '  Done. If POST /_mcp/sse returned 200 (or JSON-RPC error), the'
echo '  Streamable HTTP transport works through Cloudflare.'
echo '  Restart Cowork (close + reopen Claude Desktop) to re-attach.'
echo '====================================================================='